import { useState } from 'react';
import { 
  PieChart, 
  Pie, 
  Cell, 
  LineChart, 
  Line, 
  XAxis, 
  YAxis, 
  CartesianGrid, 
  Tooltip, 
  ResponsiveContainer 
} from 'recharts';

// ==========================================
// DUMMY DATA - BACKEND API MAPPING
// ==========================================

/**
 * KPI METRICS
 * Backend Endpoint: GET /api/dashboard/kpis?org={orgId}&range={timeRange}
 * This endpoint returns aggregated ML-processed system counts and trends
 */
const dummyKPIData = {
  totalSystems: {
    value: 847,
    delta: 12,
    trend: 'up', // 'up' or 'down'
    deltaPercent: 1.4
  },
  healthySystems: {
    value: 623,
    delta: 8,
    trend: 'up',
    deltaPercent: 1.3
  },
  warningSystems: {
    value: 189,
    delta: 15,
    trend: 'up',
    deltaPercent: 8.6
  },
  criticalSystems: {
    value: 35,
    delta: -3,
    trend: 'down',
    deltaPercent: 7.9
  },
  pendingApprovals: {
    value: 12,
    delta: 2,
    trend: 'up',
    deltaPercent: 20.0
  }
};

/**
 * RISK DISTRIBUTION
 * Backend Endpoint: GET /api/dashboard/risk-distribution
 * ML engine provides categorized system health breakdown
 */
const dummyRiskDistribution = [
