// ==========================================
// KPI CARD COMPONENT
// ==========================================
/**
 * Reusable KPI Card Component
 * Displays a single metric with delta and trend indicator
 */
function KPICard({ 
  title, 
  value, 
  delta, 
  trend, 
  deltaPercent,
  icon, 
  iconBgColor, 
  iconColor,
  onClick 
}) {
  return (
    <div 
      className="bg-white rounded-lg shadow-sm border border-gray-200 p-6 hover:shadow-md hover:-translate-y-1 transition-all duration-200 cursor-pointer"
      onClick={onClick}
    >
      <div className="flex items-start justify-between mb-4">
        <div className="flex-1">
          <p className="text-sm text-gray-600 mb-1">{title}</p>
          <p className="text-3xl font-bold text-gray-900">
            {value.toLocaleString()}
          </p>
        </div>
        <div className={`p-3 rounded-lg ${iconBgColor}`}>
          <span className={`text-2xl ${iconColor}`}>{icon}</span>
        </div>
      </div>

      {/* Delta Indicator */}
      <div className="flex items-center gap-2">
        <div className={`flex items-center gap-1 px-2 py-1 rounded ${
          trend === 'up' 
            ? delta > 0 
              ? 'bg-red-50 text-red-700' 
              : 'bg-green-50 text-green-700'
            : delta < 0
              ? 'bg-green-50 text-green-700'
              : 'bg-red-50 text-red-700'
        }`}>
          <span className="text-sm font-semibold">
            {trend === 'up' ? '↑' : '↓'} {Math.abs(delta)}
          </span>
        </div>
        <span className="text-xs text-gray-500">
          {deltaPercent}% vs last period
        </span>
      </div>
    </div>
  );
}

export default AdminDashboard;
